/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
parm(in:&Mode, in:&EmpCod, in:&FilCod);

NoAccept(FilCod);
NoAccept(FilCodPas);
EmpCod = &EmpCod if not &EmpCod.IsEmpty();
noaccept(EmpCod) if not &EmpCod.IsEmpty();
FilCod = &FilCod if not &FilCod.IsEmpty();
FilQctHomHost.Visible = &Context.pesCod = -1;
FilQctHomHost_Cell.Class = !'Invisible' If not(&Context.pesCod = -1);
FilQctHomHost_Cell.Class = !'col-xs-12 col-sm-4 DataContentCell' If &Context.pesCod = -1;
FilQctProHost.Visible = &Context.pesCod = -1;
FilQctProHost_Cell.Class = !'Invisible' If not(&Context.pesCod = -1);
FilQctProHost_Cell.Class = !'col-xs-12 col-sm-4 DataContentCell' If &Context.pesCod = -1;
tbIndustria.Visible = (FilTipAtiv = '0');
Error(Format('WWP_RequiredAttribute','UF de S.T')) if FilUfeCodST.IsEmpty();
Error(Format('WWP_RequiredAttribute','Insc.Est. S.T.')) if FilUfeInsST.IsEmpty();
Error(Format('WWP_RequiredAttribute','Tabela')) if FilTabCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Telefone Filial')) if FilFonNum.IsEmpty();
Error(Format('WWP_RequiredAttribute','Contato')) if FilCon.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Cep')) if FilCep.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Logradouro')) if FilLog.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Número')) if FilNro.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Bairro')) if FilBai.IsEmpty();
Error(Format('WWP_RequiredAttribute','Cidade')) if FilCidCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Razão Social')) if FilRaz.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Nome Fantasia')) if FilFan.IsEmpty();
Error(Format('WWP_RequiredAttribute','Filial Cnpj')) if FilCpj.IsEmpty();
Error(Format('WWP_RequiredAttribute','Pessoa da Filial')) if FilPesCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','FilialSocio')) if FilPesSoc.IsEmpty();
Default(EmpCod,&context.EmpCod);
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

Default(EmpCod, &Context.EmpCod);

UltimoCodigoEmpresa.Call(domParCod.FILIAL, &Context.EmpCod, 0, FilCod)
	If insert and FilCod.IsEmpty() 
	on AfterValidate;

FormataCEP.Call(FilCep, FilCep);

FormataFoNE.Call(FilFonNum, FilFonNum) 
	if after(FilFonNum);
FormataFoNE.Call(FilFonNum2, FilFonNum2) 
	if after(FilFonNum2);
FormataFoNE.Call(FilFonNum3, FilFonNum3) 
	if after(FilFonNum3);

ValidaCpfCnpj.Call(FilCpj, &ErroValidacao, 'S');
Error('Cnpj informado, inválido!') 
	If &ErroValidacao = 1; 

 ValidaCpfCnpj.Call(FilCtaCnpj, &ErroCta, 'S');
Error('CNPJ CONTADOR informado, inválido!') 
	If &ErroCta = 1 and (not FilCtaCnpj.IsEmpty() and not FilCtaCnpj.IsNull());

ValidaCpfCnpj.Call(FilAutXml, &ErroAutXml, 'S');
Error('CNPJ|CPF informado, inválido!') 
	If &ErroAutXml = 1;

Error('CST PIS e COFINS deve ser de entrada e não de Saída!') if val(FilPadCstPisCof.ToString()) > 0 and val(FilPadCstPisCof.ToString()) < 50;
FilFan = FilRaz 
	if After(FilRaz) and FilFan.IsEmpty();
FilCodRazSugg = FilCodRazSugg_Formula;

prompt(promptFuncionario, EmpCod, FilPesSoc);
prompt(promptCliente, EmpCod, FilPesCod);
Prompt(PromptCidade, EmpCod, FilCidCod);
prompt(PromptLocalCobranca, EmpCod, FilCbrCod);
Prompt(PromptTabelaPreco, EmpCod, &TabCod, &TabDataIni, StatusTabela.NormalAtiva, FilTabCod);
Prompt(PromptTabelaPreco, EmpCod, &TabCod, &TabDataIni, StatusTabela.Promocao, FilTabPrmCod);
